import { NextResponse } from 'next/server';
import { loadDiffData, getSampleDiffData } from '@/lib/difit-loader';

export async function GET() {
  try {
    // Try to load real diff data
    const diffData = await loadDiffData();
    return NextResponse.json(diffData);
  } catch (error) {
    console.error('Failed to load diff data:', error);

    // Fallback to sample data in case of error
    const sampleData = getSampleDiffData();
    return NextResponse.json(sampleData);
  }
}

