import { useState, useEffect } from 'react';
import { DifitEmbed } from './DifitEmbed';
import { DiffResponse } from '@/types/diff';

interface DifitClientProps {
  diffResponse: DiffResponse;
}

export function DifitClient({ diffResponse }: DifitClientProps) {
  const [height, setHeight] = useState('700px');

  useEffect(() => {
    const updateHeight = () => {
      setHeight(window.innerWidth < 640 ? '500px' : '700px');
