'use client';

import { useState, useEffect } from 'react';
import { FileDiff, DiffResponse } from '@/types/diff';
import { FileHeader } from './diff/FileHeader';
import { DiffContent } from './diff/DiffContent';

interface DifitEmbedProps {
  diffData: DiffResponse;
  height?: string;
  theme?: 'light' | 'dark';
}

export function DifitEmbed({ diffData, height = '600px', theme = 'dark' }: DifitEmbedProps) {
  const [expandedFiles, setExpandedFiles] = useState<Set<string>>(new Set());
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    // Expand first 3 files by default
    const firstThreeFiles = diffData.files.slice(0, 3).map((f) => f.path);
    setExpandedFiles(new Set(firstThreeFiles));
  }, [diffData.files]);

  const toggleFile = (filePath: string) => {
    setExpandedFiles((prev) => {
      const next = new Set(prev);
      if (next.has(filePath)) {
        next.delete(filePath);
      } else {
        next.add(filePath);
      }
      return next;
    });
  };

  if (!mounted) {
    return (
      <div className="bg-github-bg-secondary rounded-lg animate-pulse" style={{ height }}>
        <div className="p-4">
          <div className="h-4 bg-github-bg-tertiary rounded w-1/4 mb-2"></div>
          <div className="h-4 bg-github-bg-tertiary rounded w-1/2"></div>
        </div>
      </div>
    );
  }

  return (
    <div
      className={`rounded-lg border border-github-border overflow-hidden ${theme === 'dark' ? 'dark' : ''}`}
      style={{ height }}
    >
      <div className="bg-github-bg-secondary border-b border-github-border p-3 sm:p-4">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2">
          <div className="flex flex-col sm:flex-row sm:items-center gap-2 sm:gap-4">
            <h3 className="text-base sm:text-lg font-semibold text-github-text-primary">
              Changes from {diffData.baseCommitish} to {diffData.targetCommitish}
            </h3>
            <span className="text-xs sm:text-sm text-github-text-secondary">
              {diffData.files.length} files changed
            </span>
          </div>
          <div className="flex items-center gap-2 text-xs sm:text-sm">
            <span className="text-github-success">
              +{diffData.files.reduce((sum, f) => sum + f.additions, 0)}
            </span>
            <span className="text-github-danger">
              -{diffData.files.reduce((sum, f) => sum + f.deletions, 0)}
            </span>
          </div>
        </div>
      </div>

      <div
        className="overflow-y-auto bg-github-bg-primary"
        style={{ height: `calc(${height} - 65px)` }}
      >
        {diffData.files.map((file) => (
          <div key={file.path} className="border-b border-github-border last:border-b-0">
            <FileHeader
              file={file}
              isExpanded={expandedFiles.has(file.path)}
              onToggle={() => toggleFile(file.path)}
            />
            {expandedFiles.has(file.path) && <DiffContent file={file} />}
          </div>
        ))}
      </div>
    </div>
  );
}

