import { FileDiff, Line } from '@/types/diff';
import { getLanguageFromPath } from './syntax-utils';
import Prism from 'prismjs';
import { useEffect } from 'react';

// Import common language support
import 'prismjs/components/prism-javascript';
import 'prismjs/components/prism-typescript';
import 'prismjs/components/prism-jsx';
import 'prismjs/components/prism-tsx';
import 'prismjs/components/prism-css';
import 'prismjs/components/prism-json';
import 'prismjs/components/prism-markdown';
import 'prismjs/components/prism-yaml';
import 'prismjs/components/prism-bash';
import 'prismjs/components/prism-python';

interface DiffContentProps {
  file: FileDiff;
}

export function DiffContent({ file }: DiffContentProps) {
  const language = getLanguageFromPath(file.path);

  useEffect(() => {
    // Highlight syntax after render
    Prism.highlightAll();
  }, [file]);

  if (file.isBinary) {
    return (
      <div className="px-4 py-8 text-center text-github-text-secondary">Binary file not shown</div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full border-collapse">
        <tbody>
          {file.chunks.map((chunk, chunkIndex) => (
            <tr key={chunkIndex}>
              <td
                colSpan={3}
                className="bg-github-bg-tertiary px-4 py-1 text-xs text-github-text-secondary font-mono"
              >
                {chunk.header}
              </td>
            </tr>
          ))}
          {file.chunks.flatMap((chunk) =>
            chunk.lines.map((line, lineIndex) => (
              <tr key={`${chunk.header}-${lineIndex}`} className={getLineClassName(line.type)}>
                <td className="w-12 px-2 py-0 text-right select-none text-github-text-muted text-xs font-mono">
                  {line.oldNumber || ''}
                </td>
                <td className="w-12 px-2 py-0 text-right select-none text-github-text-muted text-xs font-mono">
                  {line.newNumber || ''}
                </td>
                <td className="px-4 py-0 font-mono text-sm whitespace-pre">
                  <span className="select-none mr-2">{getLinePrefix(line.type)}</span>
                  {language ?
                    <code
                      className={`language-${language}`}
                      dangerouslySetInnerHTML={{
                        __html: Prism.highlight(
                          line.content,
                          Prism.languages[language] || Prism.languages.plain,
                          language
                        ),
                      }}
                    />
                  : <span>{line.content}</span>}
                  {line.noNewline && (
                    <span className="text-github-text-muted text-xs block mt-1">
                      \ No newline at end of file
                    </span>
                  )}
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

function getLineClassName(type: Line['type']): string {
  switch (type) {
    case 'added':
      return 'bg-green-50 dark:bg-green-900/20';
    case 'deleted':
      return 'bg-red-50 dark:bg-red-900/20';
    default:
      return '';
  }
}

function getLinePrefix(type: Line['type']): string {
  switch (type) {
    case 'added':
      return '+';
    case 'deleted':
      return '-';
    default:
      return ' ';
  }
}

