### 7. DifitFullEmbed.tsxコンポーネント作成

`landing/components/DifitFullEmbed.tsx`：

```typescript
'use client';

import { useState, useEffect, useRef } from 'react';

interface DifitFullEmbedProps {
  height?: string;
  className?: string;
}

export function DifitFullEmbed({ height = '800px', className = '' }: DifitFullEmbedProps) {
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data.type === 'difit-height') {
        if (iframeRef.current) {
          iframeRef.current.style.height = `${event.data.height}px`;
        }
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  return (
    <div className={`relative ${className}`}>
      {isLoading && (
        <div
          className="absolute inset-0 flex items-center justify-center bg-github-bg-secondary"
          style={{ height }}
        >
          <div className="text-github-text-secondary">Loading difit...</div>
        </div>
      )}
      <iframe
        ref={iframeRef}
        src="/difit/index-static.html"
        className="w-full border-0"
        style={{ height }}
        onLoad={() => setIsLoading(false)}
        title="difit viewer"
        sandbox="allow-scripts allow-same-origin"
      />
    </div>
  );
}
```

### 8. 高さ自動調整のためのメッセージング

App.tsxに追加：

```typescript
// 高さの変更を親ウィンドウに通知
useEffect(() => {
  if (isStaticMode && window.parent !== window) {
    const observer = new ResizeObserver(() => {
      const height = document.documentElement.scrollHeight;
      window.parent.postMessage({ type: 'difit-height', height }, '*');
    });

    observer.observe(document.body);
    return () => observer.disconnect();
  }
}, [isStaticMode]);
```

