import { getLatestTagDiff, TagDiffData } from './git-utils';
import fs from 'fs/promises';
import path from 'path';

const CACHE_FILE = '.difit-cache.json';

export async function loadDiffData(): Promise<TagDiffData> {
  // In production, try to load from cache first
  if (process.env.NODE_ENV === 'production') {
    try {
      const cachePath = path.join(process.cwd(), CACHE_FILE);
      const cacheContent = await fs.readFile(cachePath, 'utf-8');
      const cachedData = JSON.parse(cacheContent) as TagDiffData;

      // Check if cache is recent (within 1 hour)
      const cacheAge = Date.now() - new Date(cachedData.generatedAt).getTime();
      if (cacheAge < 60 * 60 * 1000) {
        return cachedData;
      }
    } catch (error) {
      // Cache doesn't exist or is invalid, continue to generate new data
    }
  }

  // Generate fresh diff data
  const diffData = await getLatestTagDiff();

  // Limit the size of the diff for performance
  const limitedDiffData = limitDiffSize(diffData);

  // Save to cache in production
  if (process.env.NODE_ENV === 'production') {
    try {
      const cachePath = path.join(process.cwd(), CACHE_FILE);
      await fs.writeFile(cachePath, JSON.stringify(limitedDiffData, null, 2));
    } catch (error) {
      console.error('Failed to write cache:', error);
    }
  }

  return limitedDiffData;
}

function limitDiffSize(diffData: TagDiffData): TagDiffData {
  const MAX_FILES = 20;
  const MAX_CHUNKS_PER_FILE = 10;
  const MAX_LINES_PER_CHUNK = 50;

  // If the diff is small enough, return as is
  if (diffData.diffResponse.files.length <= MAX_FILES) {
    return diffData;
  }

  // Otherwise, limit the size
  return {
    ...diffData,
    diffResponse: {
      ...diffData.diffResponse,
      files: diffData.diffResponse.files.slice(0, MAX_FILES).map((file) => ({
        ...file,
        chunks: file.chunks.slice(0, MAX_CHUNKS_PER_FILE).map((chunk) => ({
          ...chunk,
          lines: chunk.lines.slice(0, MAX_LINES_PER_CHUNK),
        })),
      })),
    },
  };
}

