import simpleGit from 'simple-git';
import { execSync } from 'child_process';
import path from 'path';
import { DiffResponse, FileDiff, Chunk, Line } from '@/types/diff';

const git = simpleGit({
  baseDir: path.resolve(process.cwd(), '../..'), // Go to difit root
  binary: 'git',
  maxConcurrentProcesses: 6,
});

export interface TagDiffData {
  fromTag: string;
  toTag: string;
  diffResponse: DiffResponse;
  generatedAt: string;
}

export async function getGitTags(): Promise<string[]> {
  const tags = await git.tags(['--sort=-version:refname']);
  return tags.all.filter((tag) => tag.startsWith('v'));
}

export async function getLatestTagDiff(): Promise<TagDiffData> {
  try {
    const tags = await getGitTags();

    if (tags.length < 2) {
      throw new Error('Not enough tags to create diff');
    }

    const latestTag = tags[0];
    const previousTag = tags[1];

    // Get the diff between two tags
    const diffText = await git.diff([`${previousTag}...${latestTag}`]);

    // Parse the diff into DiffResponse format
    const diffResponse = await parseDiffToDiffResponse(previousTag, latestTag, diffText);

    return {
      fromTag: previousTag,
      toTag: latestTag,
      diffResponse,
      generatedAt: new Date().toISOString(),
    };
  } catch (error) {
    console.error('Error getting tag diff:', error);
    throw error;
  }
}

async function parseDiffToDiffResponse(
  fromTag: string,
  toTag: string,
  diffText: string
): Promise<DiffResponse> {
  // Get commit information
  const commitInfo = await git.show([toTag, '--format=%H|%an|%ae|%at|%s', '-s']);
  const [hash, authorName, authorEmail, timestamp, message] = commitInfo.split('|');

  // Get file list with stats
  const stats = await git.diff([`${fromTag}...${toTag}`, '--stat=1000,1000']);
  const files = await parseDiffFiles(diffText, stats);

  return {
    commit: `${fromTag}...${toTag}`,
    baseCommitish: fromTag,
    targetCommitish: toTag,
    mode: 'side-by-side',
    files,
    commitInfo: {
      hash: hash.trim(),
      author: {
        name: authorName.trim(),
        email: authorEmail.trim(),
      },
      date: new Date(parseInt(timestamp) * 1000).toISOString(),
      message: message.trim(),
    },
  };
}

async function parseDiffFiles(diffText: string, statsText: string): Promise<FileDiff[]> {
  const files: FileDiff[] = [];
  const fileDiffs = diffText.split(/^diff --git /m).filter(Boolean);

  // Parse stats to get additions/deletions
  const statsMap = new Map<string, { additions: number; deletions: number }>();
  const statsLines = statsText.split('\n');
  for (const line of statsLines) {
    const match = line.match(/^\s*(.+?)\s*\|\s*(\d+)\s*([\+\-]+)/);
    if (match) {
      const [, filePath, , changes] = match;
      const additions = (changes.match(/\+/g) || []).length;
      const deletions = (changes.match(/-/g) || []).length;
      statsMap.set(filePath.trim(), { additions, deletions });
    }
  }

  for (const fileDiff of fileDiffs) {
    const fileMatch = fileDiff.match(/a\/(.+?) b\/(.+?)\n/);
    if (!fileMatch) continue;

    const [, oldPath, newPath] = fileMatch;
    const isNewFile = fileDiff.includes('new file mode');
    const isDeletedFile = fileDiff.includes('deleted file mode');
    const isBinary = fileDiff.includes('Binary files');

    const stats = statsMap.get(newPath) || { additions: 0, deletions: 0 };

    // Parse chunks
    const chunks: Chunk[] = [];
    const chunkMatches = [...fileDiff.matchAll(/^@@\s+-(\d+),?(\d*)\s+\+(\d+),?(\d*)\s+@@(.*)$/gm)];

    for (let i = 0; i < chunkMatches.length; i++) {
      const chunkMatch = chunkMatches[i];
      const [fullMatch, oldStart, oldCount, newStart, newCount, header] = chunkMatch;

      const chunkStartIndex = chunkMatch.index! + fullMatch.length;
      const nextChunkIndex = chunkMatches[i + 1]?.index || fileDiff.length;
      const chunkContent = fileDiff.substring(chunkStartIndex, nextChunkIndex);

      const lines = parseChunkLines(chunkContent, parseInt(oldStart), parseInt(newStart));

      chunks.push({
        header: `@@ -${oldStart},${oldCount || '1'} +${newStart},${newCount || '1'} @@${header}`,
        lines,
      });
    }

    files.push({
      path: newPath,
      oldPath: isNewFile ? null : oldPath,
      additions: stats.additions,
      deletions: stats.deletions,
      chunks,
      isNew: isNewFile,
      isDeleted: isDeletedFile,
      isBinary,
    });
  }

  return files;
}

function parseChunkLines(content: string, oldStart: number, newStart: number): Line[] {
  const lines: Line[] = [];
  const contentLines = content.split('\n').filter((line) => line !== '');

  let oldLineNum = oldStart;
  let newLineNum = newStart;

  for (const line of contentLines) {
    const firstChar = line[0];
    const content = line.substring(1);

    if (firstChar === '-') {
      lines.push({
        type: 'deleted',
        content,
        oldNumber: oldLineNum++,
        newNumber: null,
      });
    } else if (firstChar === '+') {
      lines.push({
        type: 'added',
        content,
        oldNumber: null,
        newNumber: newLineNum++,
      });
    } else if (firstChar === ' ') {
      lines.push({
        type: 'unchanged',
        content,
        oldNumber: oldLineNum++,
        newNumber: newLineNum++,
      });
    } else if (firstChar === '\\') {
      // Handle "\ No newline at end of file"
      const lastLine = lines[lines.length - 1];
      if (lastLine) {
        lastLine.noNewline = true;
      }
    }
  }

  return lines;
}

