blobs.55f23a1:landing/scripts/build-static-dif:
import { loadDiffData } from '../lib/difit-loader';
import fs from 'fs/promises';
import path from 'path';

async function buildStaticDifit() {
  console.log('Building static difit data...');

  try {
    // diffデータを生成
    const diffData = await loadDiffData();

    // 静的データとして保存
    const staticDataPath = path.join(process.cwd(), 'public/difit/diff-data.json');
    await fs.mkdir(path.dirname(staticDataPath), { recursive: true });
    await fs.writeFile(staticDataPath, JSON.stringify(diffData.diffResponse, null, 2));

    console.log('Static diff data generated successfully at:', staticDataPath);
    console.log('From tag:', diffData.fromTag, 'To tag:', diffData.toTag);
  } catch (error) {
    console.error('Failed to build static difit:', error);
    process.exit(1);
  }
}

// スクリプトとして実行
buildStaticDifit();

