blobs.55f23a1:landing/types/diff.ts:
// Copy types from difit's types/diff.ts
export interface DiffResponse {
  commit: string;
  baseCommitish?: string;
  targetCommitish?: string;
  mode?: string;
  files: FileDiff[];
  commitInfo?: CommitInfo;
  clearComments?: boolean;
}

export interface FileDiff {
  path: string;
  oldPath: string | null;
  additions: number;
  deletions: number;
  chunks: Chunk[];
  isNew?: boolean;
  isDeleted?: boolean;
  isBinary?: boolean;
}

export interface Chunk {
  header: string;
  lines: Line[];
}

export interface Line {
  type: 'added' | 'deleted' | 'unchanged';
  content: string;
  oldNumber: number | null;
  newNumber: number | null;
  noNewline?: boolean;
}

export interface CommitInfo {
  hash: string;
  author: {
    name: string;
    email: string;
  };
  date: string;
  message: string;
}

export type LineNumber = number | `${number}-${number}`;

export interface Comment {
  id: string;
  file: string;
  line: LineNumber;
  body: string;
  codeContent?: string;
  createdAt: string;
}

