      reject(new Error('Timed out while starting background difit server'));
    }, 10_000);
    let stderr = '';
    let settled = false;

    const finish = (callback: () => void) => {
      if (settled) {
        return;
      }
      settled = true;
      clearTimeout(timeout);
      callback();
    };

    child.stdout.on('data', (chunk: string) => {
      const line = chunk
        .split(/\r?\n/u)
        .map((value) => value.trim())
        .find((value) => value.length > 0);

