    child.once('error', (error) => {
      finish(() => {
        reject(error);
      });
    });

    child.once('exit', (code) => {
      finish(() => {
        const trimmedStderr = stderr.trim();
        reject(
          new Error(
            trimmedStderr || `Background difit server exited early (code ${code ?? 'unknown'})`,
