type MarkdownRenderBlock = {
  kind: 'markdown';
  type: PreviewBlockType;
  lines: string[];
};

type FencedCodeRenderBlock = {
  kind: 'fenced-code';
  lines: PreviewLineEntry[];
};

type PreviewRenderBlock = MarkdownRenderBlock | FencedCodeRenderBlock;

type FenceInfo = {
  marker: '`' | '~';
